const laws = [{"id": "labor_001", "name": "نظام العمل - الأحكام العامة", "text": "المادة الأولى: تسري أحكام هذا النظام على العقود المبرمة لأداء عمل في المملكة العربية السعودية. المادة الثانية: لا يسري هذا النظام على موظفي الحكومة والهيئات والمؤسسات العامة وعمال الزراعة والرعي الطبيعي. المادة الثالثة: العامل كل شخص طبيعي يعمل لمصلحة صاحب عمل وتحت إدارته أو إشرافه مقابل أجر. المادة الرابعة: صاحب العمل كل شخص طبيعي أو اعتباري يستخدم عاملاً أو أكثر مقابل أجر. المادة الخامسة: عند العمل لأقل من ثلاثة أشهر يعتبر العامل في فترة تجربة ما لم يتفق على خلاف ذلك."}, {"id": "labor_002", "name": "نظام العمل - إنهاء العقد والتعويضات", "text": "المادة الثمانون: إذا أنهى صاحب العمل العقد دون سبب مشروع وجب عليه تعويض العامل عن مدة الخدمة بواقع أجر شهر عن كل سنة من سنوات الخدمة. المادة الواحدة والثمانون: يستحق العامل مكافأة نهاية الخدمة بواقع أجر نصف شهر عن كل سنة من السنوات الخمس الأولى وأجر شهر عن كل سنة بعد ذلك. المادة الثانية والثمانون: يحق للعامل إنهاء عقده دون إشعار مسبق إذا أخل صاحب العمل بالتزاماته التعاقدية."}, {"id": "company_001", "name": "نظام الشركات - الشركة ذات المسؤولية المحدودة", "text": "المادة الأولى: الشركة ذات المسؤولية المحدودة شركة تتكون من شريك أو أكثر ولا يسأل كل منهم إلا بمقدار حصته في رأس المال. المادة الثانية: يجب ألا يقل رأس مال الشركة عن عشرة آلاف ريال سعودي. المادة الثالثة: تتكون الشركة من عقد تأسيس يتضمن اسم الشركة وغرضها ورأس مالها وحصص الشركاء. المادة الرابعة: تُدار الشركة بواسطة مدير أو أكثر من الشركاء أو من غيرهم."}, {"id": "vat_001", "name": "نظام ضريبة القيمة المضافة", "text": "المادة الأولى: تُفرض ضريبة القيمة المضافة بنسبة خمسة عشر بالمائة على جميع السلع والخدمات المُورَّدة في المملكة. المادة الثانية: يلتزم كل شخص خاضع للضريبة بالتسجيل لدى الهيئة العامة للزكاة والضريبة والجمارك إذا تجاوز حجم أعماله حد التسجيل الإلزامي. المادة الثالثة: حد التسجيل الإلزامي مائة وثمانية وثمانون ألف ريال سعودي سنوياً."}, {"id": "data_001", "name": "نظام حماية البيانات الشخصية", "text": "المادة الأولى: يهدف هذا النظام إلى حماية البيانات الشخصية من الجمع والمعالجة غير المشروعة وصون الخصوصية. المادة الثانية: لا يجوز جمع البيانات الشخصية أو معالجتها إلا بموافقة صريحة من صاحبها. المادة الثالثة: يحق لصاحب البيانات الاطلاع على بياناته وطلب تصحيحها أو حذفها. المادة الرابعة: يُعاقب على مخالفة أحكام هذا النظام بغرامة مالية لا تتجاوز خمسة ملايين ريال."}, {"id": "cyber_001", "name": "نظام مكافحة الجرائم المعلوماتية", "text": "المادة الأولى: يُعاقب بالسجن مدة لا تزيد على سنة وبغرامة لا تزيد على خمسمائة ألف ريال كل من يرتكب جريمة معلوماتية. المادة الثانية: الجريمة المعلوماتية كل فعل يُرتكب متضمناً استخدام الحاسب الآلي أو الشبكة المعلوماتية بصورة غير مشروعة. المادة الثالثة: يُعاقب بالسجن مدة لا تزيد على أربع سنوات كل من يصل بطريقة غير مشروعة إلى بيانات تمس النظام العام."}];
const results = [];
const chunkSize = 600;
const overlap = 80;
for (const law of laws) {
  const text = law.text;
  let start = 0, idx = 0;
  while (start < text.length) {
    const end = Math.min(start + chunkSize, text.length);
    const chunk = text.substring(start, end).trim();
    if (chunk.length > 30) {
      results.push({ json: { chunk_id: law.id + '_c' + idx, chunk_text: chunk, law_name: law.name, law_id: law.id } });
      idx++;
    }
    if (end >= text.length) break;
    start += chunkSize - overlap;
  }
}
return results;

const embedding = $json.embedding;
const prev = $('📚 تحميل وتقسيم النصوص').item.json;
return {
  ids: [prev.chunk_id],
  embeddings: [embedding],
  documents: [prev.chunk_text],
  metadatas: [{ law_name: prev.law_name, law_id: prev.law_id }],
  chunk_id: prev.chunk_id,
  law_name: prev.law_name
};
